import { type ReactNode } from 'react';
import useIntl from 'react-intl/src/components/useIntl.js';

import { OVERLAY_TOOLTIP_MESSAGES } from '../messages.js';
import { useTooltipSnapshot } from '../selectors.js';
import { actionsPlaceholderTextAnimated } from './global-actions/actions.sty.js';
import { GlobalActions } from './global-actions/GlobalActions.js';

/**
 * Props for the `ChartTooltip.Footer` slot.
 * @public
 */
export interface FooterProps {
  /** Global actions rendered in the footer when the tooltip is pinned. */
  actions: ReactNode[];
  /** Text shown in the footer when the tooltip is not yet pinned. Defaults to a built-in pin prompt message. */
  unpinnedPlaceholderText: string | undefined;
}

/** @public */
export const Footer = ({ actions, unpinnedPlaceholderText }: FooterProps) => {
  const intl = useIntl();
  const { pinned } = useTooltipSnapshot();

  if (pinned) {
    return actions.length > 0 ? <GlobalActions actions={actions} /> : null;
  }

  const placeholderText =
    unpinnedPlaceholderText ??
    intl.formatMessage(OVERLAY_TOOLTIP_MESSAGES.unpinnedPlaceholderMessage);

  return (
    <div className={actionsPlaceholderTextAnimated}>{placeholderText}</div>
  );
};
